const runId = new Date().toISOString();
const runIdSafe = runId.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
const queueName = `test_queue_${runIdSafe.slice(0, 24)}`;
const workerId = `test_worker_${runIdSafe.slice(0, 24)}`;
const workerName = `Test Worker ${runId}`;

const context = {
  run_id: runId,
  worker_workflow_id: 'REPLACE_WITH_WORKFLOW_ID',
  queue_name: queueName,
  worker_id: workerId,
  worker_name: workerName,
  api_key: null,
  task_uuid_a: null,
  task_uuid_long: null,
  task_uuid_b: null,
  results: []
};

return [{ json: { context } }];

const prev = $items('Init Test Context')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.create_queue === true || result.create_queue === 't' || result.create_queue === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'create_queue',
  success: ok && !error,
  expected: 'create_queue returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{ json: { context } }];

const prev = $items('After Create Queue')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const apiKey = result.api_key || null;
const ok = !!apiKey;
const error = result.error || result.message || null;

const testResult = {
  name: 'register_worker',
  success: ok && !error,
  expected: 'api_key returned from register_worker',
  actual: result,
  error
};

const context = { ...prev, api_key: apiKey || prev.api_key, results: [...prev.results, testResult] };

return [{ json: { context } }];

const prev = $items('After Register Worker')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const taskUuid = result.task_uuid || result.enqueue_task || null;
const ok = typeof taskUuid === 'string' && taskUuid.length >= 10;
const error = result.error || result.message || null;

const testResult = {
  name: 'enqueue_task_a',
  success: ok && !error,
  expected: 'enqueue_task returns uuid',
  actual: result,
  error
};

const context = { ...prev, task_uuid_a: taskUuid, results: [...prev.results, testResult] };

return [{ json: { context } }];

