const prev = $items('After Long Task Status')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.status === 'completed';
const error = result.error || result.message || null;

const testResult = {
  name: 'task_example_b_status',
  success: ok && !error,
  expected: 'status completed',
  actual: result,
  error
};

const results = [...prev.results, testResult];
const passed = results.filter(r => r.success).length;
const failed = results.length - passed;

return [{
  json: {
    run_id: prev.run_id,
    queue_name: prev.queue_name,
    worker_id: prev.worker_id,
    api_key_prefix: prev.api_key ? String(prev.api_key).slice(0, 10) : null,
    summary: { total: results.length, passed, failed },
    results
  }
}];
